CREATE TRIGGER [Global].[Coater_History]ON [Global].[Coater]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.CoaterId IS NOT NULL AND d.CoaterId IS NULL THEN 'I' 		WHEN i.CoaterId IS NOT NULL AND d.CoaterId IS NOT NULL THEN 'U' 		WHEN i.CoaterId IS NULL AND d.CoaterId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.CoaterId = d.CoaterId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.Global_Coater([CoaterId], [EquipmentId], [Number], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [CoaterId], [EquipmentId], [Number], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.Global_Coater([CoaterId], [EquipmentId], [Number], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [CoaterId], [EquipmentId], [Number], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND